// Idempotency: setIfAbsent prevents duplicate workspace creation on resume
const lockKey = `workspace:${userId}:${tenantId}`;
const locked = await this.memory.setIfAbsent(lockKey, 'provisioning', 3600);
if (!locked.data) return DataProcessResult.success({ workspaceId: existing.workspaceId });
// Use ITenantRegistry — not a raw database INSERT
return this.tenantRegistry.createTenant(workspaceId, { ownerId: userId });
